// Dart imports:
import 'dart:io';

// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:path/path.dart';
import 'package:uuid/uuid.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/clients/auth/auth_client.dart';
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/enums/app_role.dart';
import 'package:baseball_detector_flutter/data/models/enums/unit_type.dart';
import 'package:baseball_detector_flutter/data/repositories/repository.dart';
import 'package:baseball_detector_flutter/providers/auth_client_provider.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';
import '../../_common/create_container.dart';
import '../../_common/expect_api_response.dart';
import '../../_common/http_test_flutter_binding.dart';
import '../../_common/sql_utils.dart';
import '../../_testdata/generators/data/balls.dart';
import '../../_testdata/generators/data/notification.dart';
import '../../_testdata/generators/data/pitch_types.dart';
import '../../_testdata/generators/data/players.dart';
import '../../_testdata/generators/data/resources.dart';
import '../../_testdata/generators/data/sessions.dart';
import '../../_testdata/generators/data/teams.dart';
import '../../_testdata/generators/data/users.dart';

void main() {
  HttpTestFlutterBinding();

  final testDataDir = join(dirname(Platform.script.path), 'test', '_testdata');

  late AuthClient authClient;
  late Repository repository;
  setUpAll(() async {
    final ref = await createContainer();

    authClient = ref.read(authClientProvider);
    repository = ref.read(repositoryProvider);
  });

  setUpAll(() async {
    await restoreDeletedRecords();
  });

  group('Testing APIServerRepository (team_admin, read)', () {
    // sign in
    setUpAll(() async {
      final response = await authClient.signInWithPassword(
          'team_admin@example.co.jp', 'test1234', true);
      expectRight(response);
    });

    test('getSessions', () async {
      final response = await repository.getSessions(
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final sessions = response.right.sessions;
      expectSessions(sessions, teamId: teamMultipleUsers.id!);
    });

    test('getSessionDetail', () async {
      final response = await repository.getSessionDetail(
          teamId: sessionTeam.teamId!, sessionId: sessionTeam.id!);
      expectRight(response);

      final session = response.right;
      expectSessionById(session, sessionTeam.id!);
    });

    test('getPlayers', () async {
      final response = await repository.getPlayers(
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final pagination = response.right;
      expectPlayers(pagination.players, teamId: teamMultipleUsers.id!);
    });

    test('getResources', () async {
      final response = await repository.getResources(
        teamId: teamMultipleUsers.id!,
        sessionId: sessionTeam.id!,
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final resources = response.right;
      expectResourcesBySessionId(resources.resources, sessionTeam.id!);
    });

    test('getResourceDetail', () async {
      final response = await repository.getResourceDetail(
        teamId: teamMultipleUsers.id!,
        sessionId: sessionTeam.id!,
        resourceId: resourceTeam.id!,
      );
      expectRight(response);

      final resource = response.right;
      expectResourceDetailById(resource, resourceTeam.id!);
    });

    test('getPitchTypes', () async {
      final response = await repository.getUserInfo();
      expectRight(response);
    });

    test('getUserInfo', () async {
      final response = await repository.getUserInfo();
      expectRight(response);

      final userInfo = response.right;
      expectUserInfoByUserId(userInfo, userTeamAdmin.id);
    });

    test('getTeamMembers', () async {
      final response = await repository.getTeamMembers(
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final teamUserInfos = response.right;
      final teamProfiles =
          teamUserInfos.users.map((userInfo) => userInfo.profile).toList();
      expectTeamMemberProfilesByTeamId(teamProfiles, teamMultipleUsers.id!);
    });
  });

  group('testing APIServerRepository (team_member, read)', () {
    // sign in
    setUpAll(() async {
      final response = await authClient.signInWithPassword(
          'team_member@example.co.jp', 'test1234', true);
      expectRight(response);
    });

    test('getSessions', () async {
      final response = await repository.getSessions(
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final sessions = response.right.sessions;
      expectSessions(sessions, userId: userTeamMember.id);
    });

    test('getSessionDetail', () async {
      final response = await repository.getSessionDetail(
          teamId: sessionTeamMember.teamId!, sessionId: sessionTeamMember.id!);
      expectRight(response);

      final session = response.right;
      expectSessionById(session, sessionTeamMember.id!);
    });

    test('getPlayers', () async {
      final response = await repository.getPlayers(
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final pagination = response.right;
      expectPlayers(pagination.players, userId: userTeamMember.id);
    });

    test('getResources', () async {
      final response = await repository.getResources(
        teamId: teamMultipleUsers.id!,
        sessionId: sessionTeamMember.id!,
        page: 0,
        pageSize: 10,
      );
      expectRight(response);

      final resources = response.right;
      expectResourcesBySessionId(resources.resources, sessionTeamMember.id!);
    });

    test('getResourceDetail', () async {
      final response = await repository.getResourceDetail(
        teamId: teamMultipleUsers.id!,
        sessionId: sessionTeamMember.id!,
        resourceId: resourceTeamMember.id!,
      );
      expectRight(response);

      final resource = response.right;
      expectResourceDetailById(resource, resourceTeamMember.id!);
    });

    test('getUserInfo', () async {
      final response = await repository.getUserInfo();
      expectRight(response);

      final userInfo = response.right;
      expectUserInfoByUserId(userInfo, userTeamMember.id);
    });

    test('getNotifications', () async {
      final response = await repository.getNotifications();
      expectRight(response);
      final notifications = response.right;
      expectNotifications(notifications);
    });

    test('setNotificationRead', () async {
      final response = await repository.setNotificationRead(
        notificationId: notificationRead.id,
      );
      expectRight(response);
    });
  });

  group('testing APIServerRepository (super_admin, read)', () {
    // sign in
    setUpAll(() async {
      final response = await authClient.signInWithPassword(
          'super_admin@example.co.jp', 'test1234', true);
      expectRight(response);
    });

    test('getTeams', () async {
      final response = await repository.getTeams();
      expectRight(response);
      // Since the response varies depending on the result of editing, the
      // content of the response is not verified here.
    });
  });

  group('testing APIServerRepository (team_admin, write)', () {
    // sign in
    setUpAll(() async {
      final response = await authClient.signInWithPassword(
          'team_admin_write_test@example.co.jp', 'test1234', true);
      expectRight(response);
    });

    test('addSession', () async {
      final response = await repository.addSession(
        title: 'addSession test',
        playerId: playerWriteTest.id!,
        location: 'test location',
        note: 'test note',
      );
      expectRight(response);
    });

    test('addPlayer', () async {
      final response = await repository.addPlayer(
        playerName: 'addPlayer test',
        note: 'test note',
        pitchingHand: Handedness.right,
        hittingHand: Handedness.right,
      );
      expectRight(response);
    });

    test('deleteSession', () async {
      final response = await repository.deleteSession(
        sessionId: sessionToBeDeleted.id!,
      );
      expectRight(response);
    });

    test('deletePlayer', () async {
      final response = await repository.deletePlayer(
        playerId: playerToBeDeleted.id!,
      );
      expectRight(response);
    });

    test('deleteResource', () async {
      final response = await repository.deleteResource(
        sessionId: resourceToBeDeleted.sessionId!,
        resourceId: resourceToBeDeleted.id!,
      );
      expectRight(response);
    });

    test('editPitchType', () async {
      final response = await repository.editPitchType(
        sessionId: resourceToBeDeleted.sessionId!,
        resourceId: resourceToBeDeleted.id!,
        ballId: balls[2].id!,
        pitchTypeId: pitchType1.id!,
      );
      expectRight(response);
    });

    test('editSession', () async {
      final response = await repository.editSession(
        playerId: sessionToBeEdited.playerId!,
        sessionId: sessionToBeEdited.id!,
        location: sessionToBeEdited.location!,
        note: sessionToBeEdited.note!,
        title: 'edited session',
      );
      expectRight(response);
    });

    test('editPlayer', () async {
      final response = await repository.editPlayer(
        playerId: playerToBeEdited.id!,
        name: 'Edited player',
        note: 'Edited note',
        pitchingHand: Handedness.right,
        hittingHand: Handedness.right,
      );
      expectRight(response);
    });

    test('editProfile', () async {
      final response = await repository.editProfile(
        name: 'Edited profile (team_admin)',
      );
      expectRight(response);
    });

    test('editTeam', () async {
      final response = await repository.editTeam(
        name: 'Edited team',
      );
      expectRight(response);
    });

    test('uploadProfileImage', () async {
      final response = await repository.uploadProfileImage(
        filePath: join(testDataDir, 'dummy.png'),
      );
      expectRight(response);
    });

    test('uploadTeamImage', () async {
      final response = await repository.uploadTeamImage(
        filePath: join(testDataDir, 'dummy.png'),
      );
      expectRight(response);
    });

    test('uploadPlayerImage', () async {
      final response = await repository.uploadPlayerImage(
        playerId: playerToBeEdited.id!,
        filePath: join(testDataDir, 'dummy.png'),
      );
      expectRight(response);
    });

    test('uploadVideo', () async {
      final resourceId = const Uuid().v4().toString();
      final response = await repository.uploadVideo(
        sessionId: sessionToBeEdited.id!,
        resourceId: resourceId,
        filePath: join(testDataDir, 'dummy.mp4'),
        analyzeType: 1,
        unit: UnitType.kmhCm,
        focalLengthIn35mmEquivalent: 1,
        longsideAngleOfView: 1,
        accX: 1,
        accY: 1,
        accZ: 1,
        lens: 'test lens',
        focus: 1,
        isAutoFocus: true,
        zoom: 1,
        iso: 1,
        shutterSpeed: 1,
        device: 'test device',
        recordedAt: DateTime.utc(2024, 1, 1),
        cameraMode: 'test camera mode',
      );
      expectRight(response);
    });

    test('reAnalyzeVideo', () async {
      final response = await repository.reAnalyzeVideo(
        sessionId: resourceToBeReanalyzed.sessionId!,
        resourceId: resourceToBeReanalyzed.id!,
      );
      expectRight(response);
    });

    test('editMemberRole', () async {
      final response = await repository.editMemberRole(
        userId: userToBeEdited.id,
        role: AppRole.teamManager,
      );
      expectRight(response);
    });

    test('inviteMember', () async {
      final response = await repository.inviteMember(
        email: 'invited-${DateTime.now().millisecondsSinceEpoch}@example.co.jp',
        role: AppRole.teamMember,
        name: 'Invited',
      );
      expectRight(response);
    });

    test('deactivateMember', () async {
      final response = await repository.deactivateMember(
        userId: userToBeActivated.id,
      );
      expectRight(response);
    });

    test('reactivateMember', () async {
      final response = await repository.reactivateMember(
        userId: userToBeActivated.id,
      );
      expectRight(response);
    });
  });
}

