      expect(reqJson.containsKey('isAutoFocus'), isTrue);
      expect(reqJson.containsKey('analyzeType'), isTrue);
      expect(reqJson.containsKey('unit'), isTrue);
      expect(reqJson.containsKey('zoom'), isTrue);
      expect(reqJson.containsKey('iso'), isTrue);
      expect(reqJson.containsKey('shutterSpeed'), isTrue);

      expect(reqJson['resourceId'], resourceId);
      expect(reqJson['recordedAt'], recordedAt.toIso8601String());
      expect(reqJson['longsideAngleOfView'], longsideAngleOfView);
      expect(reqJson['focalLength'], focalLength);
      expect(reqJson['accX'], accX);
      expect(reqJson['accY'], accY);
      expect(reqJson['accZ'], accZ);
      expect(reqJson['lens'], lens);
      expect(reqJson['focus'], focus);
      expect(reqJson['isAutoFocus'], isAutoFocus);
      expect(reqJson['analyzeType'], analyzeType);
      expect(reqJson['unit'], unit.toJson());
      expect(reqJson['zoom'], zoom);
