          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId1,
          createAccessibleContents({
            teamId1: [AppRole.superAdmin]
          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId1,
          createAccessibleContents({
            teamId1: [AppRole.personalUser]
          }),
        ),
        true,
      );

      // same team, another user
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId1: [AppRole.teamAdmin]
          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId1: [AppRole.teamManager]
          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId1: [AppRole.superAdmin]
          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId1: [AppRole.teamMember]
          }),
        ),
        false,
      );

      // another team, another user
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId2: [AppRole.superAdmin]
          }),
        ),
        true,
      );
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId2: [AppRole.teamAdmin]
          }),
        ),
        false,
      );
      expect(
        r.isDeletableByUser(
          userId2,
          createAccessibleContents({
            teamId2: [AppRole.teamManager]
          }),
        ),
        false,
