import 'package:freezed_annotation/freezed_annotation.dart';

part 'video_analyze_request.freezed.dart';
part 'video_analyze_request.g.dart';

@freezed
abstract class VideoAnalyzeRequest with _$VideoAnalyzeRequest {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: FieldRename.none,
    includeIfNull: false,
  )
  const factory VideoAnalyzeRequest({
    required String resourceId,
    required int analyzeType,
    DateTime? recordedAt,
    double? longsideAngleOfView,
    double? focalLength,
    double? accX,
    double? accY,
    double? accZ,
    String? lens,
    double? focus,
    bool? isAutoFocus,
    String? cameraMode,
    double? zoom,
    double? iso,
    double? shutterSpeed,
    String? device,
  }) = _VideoAnalyzeRequest;

  factory VideoAnalyzeRequest.fromJson(Map<String, dynamic> json) =>
      _$VideoAnalyzeRequestFromJson(json);
}

